import type { PresetPeriod } from '../Calendar/Calendar.types';
import type { DatePickerProps, RangeDateValue } from '../DatePicker.types';
export interface DatePickerRangeProps extends Omit<DatePickerProps, 'value' | 'onChange'> {
    value?: RangeDateValue;
    /**
     * Обработчик вызываемый при изменении значения `value`
     */
    onChange?: (date: RangeDateValue) => void;
    clearInvalidOnBlur?: boolean;
    /**
     * Массив предустановленных периодов для быстрого выбора
     */
    presetPeriods?: PresetPeriod[];
    /**
     * Обработчик выбора предустановленного периода
     */
    onPresetPeriodSelect?: (range: [string, string]) => void;
}
